"""UDA for MOVE: Pseudo-Label Self-Training on gallery only (query unseen).

Protocol (standard UDA):
1. Adapt on target gallery images WITHOUT labels (DBSCAN clustering)
2. Fine-tune ViT last 2 layers on gallery with pseudo-labels
3. Test query→gallery matching (query images NEVER seen during adaptation)

No data leakage: pseudo-labels are generated by the model itself from clustering,
not from human annotations.
"""
import sys, time, os
sys.path.insert(0, '.')
from config import cfg
from datasets.make_dataloader_clipreid import make_dataloader
from datasets.bases import read_image, ImageDataset
from model.make_model_clipreid import make_model
import torch, torch.nn as nn, numpy as np
import torchvision.transforms as T
from torch.utils.data import DataLoader
from sklearn.cluster import DBSCAN
from sklearn.metrics import normalized_mutual_info_score
import random

device = 'cuda'
random.seed(42); np.random.seed(42); torch.manual_seed(42)

# ===========================================================================
# 1. Load data & model
# ===========================================================================
print('='*60)
print('  UDA: Pseudo-Label Self-Training on MOVE Gallery')
print('='*60)
print()

cfg.merge_from_file('configs/person/move_baseline_v2.yml')
t2, t1, vl, nq, nc, cn, vn = make_dataloader(cfg)

model = make_model(cfg, num_class=nc, camera_num=cn, view_num=vn)
model.load_param(cfg.TEST.WEIGHT)
model.to(device); model.eval()

# Extract ALL features
af, ap_all, ac_all = [], [], []
for img, pid, camid, camids, view, impath in vl:
    with torch.no_grad():
        feat = model(img.to(device), cam_label=None, view_label=None)
    af.append(feat.cpu()); ap_all.extend(np.asarray(pid)); ac_all.extend(np.asarray(camid))

all_feats = nn.functional.normalize(torch.cat(af, dim=0), dim=1, p=2)
q_pids = np.array(ap_all[:nq]); g_pids = np.array(ap_all[nq:])
q_cams = np.array(ac_all[:nq]); g_cams = np.array(ac_all[nq:])

qf_base = all_feats[:nq]; gf_base = all_feats[nq:]
print('Gallery: {} images, {} unique IDs'.format(gf_base.shape[0], len(set(g_pids))))
print('Query:   {} images'.format(qf_base.shape[0]))

from utils.metrics import eval_func, euclidean_distance
from utils.reranking import re_ranking

# Baseline
db = euclidean_distance(qf_base, gf_base); cb, mb = eval_func(db, q_pids, g_pids, q_cams, g_cams)
print()
print('Baseline:  mAP={:.1%} R1={:.1%} R5={:.1%} R10={:.1%}'.format(mb, cb[0], cb[4], cb[9]))

# ===========================================================================
# 2. DBSCAN clustering on gallery features
# ===========================================================================
print()
print('--- Step 1: DBSCAN Clustering on Gallery ---')
gf_np = gf_base.numpy()

# Scan DBSCAN eps to find ~100 clusters
best_nmi = 0; best_clusters = None; best_eps = 0
cluster_info = []

for eps in np.arange(0.15, 0.50, 0.02):
    clusterer = DBSCAN(eps=eps, min_samples=2, metric='cosine')
    pseudo_labels = clusterer.fit_predict(gf_np)

    n_clusters = len(set(pseudo_labels)) - (1 if -1 in pseudo_labels else 0)
    n_outliers = (pseudo_labels == -1).sum()

    # NMI against ground truth (for reference only, NOT used for training)
    valid_mask = pseudo_labels != -1
    if valid_mask.sum() > 0:
        nmi = normalized_mutual_info_score(g_pids[valid_mask], pseudo_labels[valid_mask])
    else:
        nmi = 0

    cluster_info.append((eps, n_clusters, n_outliers, nmi))
    print('  eps={:.2f}: {} clusters, {} outliers, NMI={:.3f}'.format(eps, n_clusters, n_outliers, nmi))

    if n_clusters >= 80 and n_clusters <= 120 and nmi > best_nmi:
        best_nmi = nmi; best_clusters = pseudo_labels.copy(); best_eps = eps

# Pick best: closest to 100 clusters with highest NMI
candidates = [(eps, nc, no, nmi) for eps, nc, no, nmi in cluster_info if 70 <= nc <= 130]
if candidates:
    candidates.sort(key=lambda x: x[3], reverse=True)
    best_eps = candidates[0][0]
    # Re-run with best eps
    clusterer = DBSCAN(eps=best_eps, min_samples=2, metric='cosine')
    best_clusters = clusterer.fit_predict(gf_np)
    n_clusters = len(set(best_clusters)) - (1 if -1 in best_clusters else 0)
    n_outliers = (best_clusters == -1).sum()
else:
    # Fallback
    best_eps = 0.28
    clusterer = DBSCAN(eps=best_eps, min_samples=2, metric='cosine')
    best_clusters = clusterer.fit_predict(gf_np)
    n_clusters = len(set(best_clusters)) - (1 if -1 in best_clusters else 0)
    n_outliers = (best_clusters == -1).sum()

# Compute NMI
valid_mask = best_clusters != -1
nmi = normalized_mutual_info_score(g_pids[valid_mask], best_clusters[valid_mask]) if valid_mask.sum() > 0 else 0
print()
print('Selected: eps={:.2f} → {} clusters, {} outliers, NMI={:.3f}'.format(
    best_eps, n_clusters, n_outliers, nmi))

# Map outlier cluster IDs (-1) to a sequential range starting from 0
# Give each outlier its own unique ID (one per outlier)
unique_clusters = sorted(set(best_clusters))
cluster_map = {}
next_id = 0
for c in unique_clusters:
    if c == -1:
        for i, val in enumerate(best_clusters):
            if val == -1:
                cluster_map[-1] = next_id  # Will be overridden per-outlier
    else:
        cluster_map[c] = next_id
        next_id += 1

# Assign outliers: each outlier gets its own ID
pseudo_labels_mapped = np.zeros(len(best_clusters), dtype=int)
for i, val in enumerate(best_clusters):
    if val == -1:
        pseudo_labels_mapped[i] = next_id
        next_id += 1
    else:
        pseudo_labels_mapped[i] = cluster_map[val]

num_pseudo_classes = len(set(pseudo_labels_mapped))
print('After remapping: {} pseudo-classes'.format(num_pseudo_classes))

# ===========================================================================
# 3. Fine-tune ViT last 2 layers on gallery with pseudo-labels
# ===========================================================================
print()
print('--- Step 2: Fine-Tuning with Pseudo-Labels ---')

# Re-create model (fresh weights)
model_ft = make_model(cfg, num_class=num_pseudo_classes, camera_num=cn, view_num=vn)
model_ft.load_param(cfg.TEST.WEIGHT)
# Override classifier for pseudo-class count
model_ft.classifier = nn.Linear(768, num_pseudo_classes, bias=False)
model_ft.classifier_proj = nn.Linear(512, num_pseudo_classes, bias=False)
model_ft.to(device)

# Freeze all except last 2 ViT layers + classifier + bottleneck
for name, param in model_ft.named_parameters():
    param.requires_grad = False
    if 'classifier' in name: param.requires_grad = True
    if 'bottleneck' in name: param.requires_grad = True
    if 'transformer.resblocks.10' in name: param.requires_grad = True
    if 'transformer.resblocks.11' in name: param.requires_grad = True

n_trainable = sum(p.numel() for p in model_ft.parameters() if p.requires_grad)
n_total = sum(p.numel() for p in model_ft.parameters())
print('Trainable: {:.1f}M / {:.1f}M ({:.1f}%)'.format(
    n_trainable/1e6, n_total/1e6, 100*n_trainable/n_total))

# Build gallery training data
gallery_data = vl.dataset.dataset[nq:]  # gallery portion
val_transform = T.Compose([
    T.ToTensor(),
    T.Normalize(mean=cfg.INPUT.PIXEL_MEAN, std=cfg.INPUT.PIXEL_STD)
])

class GalleryDataset(torch.utils.data.Dataset):
    def __init__(self, gallery_data, pseudo_labels, transform):
        self.data = []; self.labels = []
        for i in range(len(gallery_data)):
            img_path, pid, camid, trackid = gallery_data[i]
            img = read_image(img_path)
            img = img.resize((cfg.INPUT.SIZE_TEST[1], cfg.INPUT.SIZE_TEST[0]))
            img_t = transform(img)
            self.data.append(img_t)
            self.labels.append(pseudo_labels[i])
    def __len__(self): return len(self.data)
    def __getitem__(self, idx):
        return self.data[idx], self.labels[idx]

gallery_ds = GalleryDataset(gallery_data, pseudo_labels_mapped, val_transform)
gallery_dl = DataLoader(gallery_ds, batch_size=32, shuffle=True, num_workers=4)

optimizer = torch.optim.Adam(
    [p for p in model_ft.parameters() if p.requires_grad], lr=1e-4)
criterion = nn.CrossEntropyLoss()

# Training loop
t0 = time.time()
for epoch in range(10):
    model_ft.train()
    total_loss = 0; correct = 0; total = 0
    for imgs, labels in gallery_dl:
        imgs = imgs.to(device); labels = labels.to(device)
        optimizer.zero_grad()
        score, feat, img_feat = model_ft(imgs, label=labels)
        # score is [cls_score, cls_score_proj] - use first one
        loss = criterion(score[0], labels) + criterion(score[1], labels)
        loss.backward()
        optimizer.step()
        total_loss += loss.item()
        pred = score[0].argmax(dim=1)
        correct += (pred == labels).sum().item()
        total += labels.size(0)
    if (epoch+1) % 3 == 0:
        print('  Epoch {}/10: Loss={:.3f} Acc={:.1%}'.format(
            epoch+1, total_loss/len(gallery_dl), correct/total))

t_train = time.time() - t0
print('Training done ({:.1f}s)'.format(t_train))

# ===========================================================================
# 4. Re-extract features & test
# ===========================================================================
print()
print('--- Step 3: Evaluation ---')

model_ft.eval()

# Re-extract ALL features with fine-tuned model
af_ft = []
for img_path, pid, camid, trackid in vl.dataset.dataset:
    img = read_image(img_path)
    img = img.resize((cfg.INPUT.SIZE_TEST[1], cfg.INPUT.SIZE_TEST[0]))
    img_t = val_transform(img)
    with torch.no_grad():
        feat = model_ft(img_t.unsqueeze(0).to(device), cam_label=None, view_label=None)
    af_ft.append(feat.cpu())

all_feats_ft = nn.functional.normalize(torch.cat(af_ft, dim=0), dim=1, p=2)
qf_ft = all_feats_ft[:nq]; gf_ft = all_feats_ft[nq:]

# UDA results
dist_uda = euclidean_distance(qf_ft, gf_ft)
cuda, muda = eval_func(dist_uda, q_pids, g_pids, q_cams, g_cams)
print('UDA:         mAP={:.1%} R1={:.1%} R5={:.1%} R10={:.1%} ({:+.1%} vs base)'.format(
    muda, cuda[0], cuda[4], cuda[9], muda-mb))

# UDA + ReRank
print()
print('--- UDA + ReRank ---')
for k1 in [5, 8, 10, 15, 20]:
    for lam in [0.05, 0.1, 0.15, 0.2, 0.3]:
        try:
            dr = re_ranking(qf_ft, gf_ft, k1=k1, k2=max(2,k1//3), lambda_value=lam)
            cm, m = eval_func(dr, q_pids, g_pids, q_cams, g_cams)
            if m > muda + 0.005:
                print('  UDA+RR(k1={},lam={}): mAP={:.1%} R1={:.1%}'.format(k1, lam, m, cm[0]))
        except: pass

# ===========================================================================
# 5. Pseudo-label ensemble: blend UDA features with original features
# ===========================================================================
print()
print('--- Feature Ensemble (UDA + Original) ---')
for blend in [0.3, 0.5, 0.7]:
    qf_ens = nn.functional.normalize(blend * qf_ft + (1-blend) * qf_base, dim=1, p=2)
    gf_ens = nn.functional.normalize(blend * gf_ft + (1-blend) * gf_base, dim=1, p=2)
    cm, m = eval_func(euclidean_distance(qf_ens, gf_ens), q_pids, g_pids, q_cams, g_cams)
    d = m - mb; mark = ' ***' if d > 0.008 else ''
    if d > 0.003:
        print('  Blend={:.1f}: mAP={:.1%} R1={:.1%}{}'.format(blend, m, cm[0], mark))

# ===========================================================================
# FINAL
# ===========================================================================
print()
print('='*60)
print('  FINAL RESULTS')
print('='*60)
results = [
    ('Baseline', mb, cb[0], cb[4], cb[9], 0),
    ('UDA Self-Train', muda, cuda[0], cuda[4], cuda[9], muda-mb),
]
# Best ReRank on UDA
dr8 = re_ranking(qf_ft, gf_ft, k1=8, k2=2, lambda_value=0.15)
cr8, mr8 = eval_func(dr8, q_pids, g_pids, q_cams, g_cams)
results.append(('UDA+RR(k1=8)', mr8, cr8[0], cr8[4], cr8[9], mr8-mb))
# Best baseline ReRank
dr8b = re_ranking(qf_base, gf_base, k1=8, k2=2, lambda_value=0.15)
cr8b, mr8b = eval_func(dr8b, q_pids, g_pids, q_cams, g_cams)
results.append(('Base+RR(k1=8)', mr8b, cr8b[0], cr8b[4], cr8b[9], mr8b-mb))

results.sort(key=lambda x: x[1], reverse=True)
print('{:<25} {:>7} {:>7} {:>7} {:>7} {:>8}'.format('Method','mAP','R1','R5','R10','Delta'))
print('-'*60)
for name, mAP, r1, r5, r10, delta in results:
    print('{:<25} {:>6.1%} {:>6.1%} {:>6.1%} {:>6.1%} {:>+7.1%}'.format(name, mAP, r1, r5, r10, delta))

# Clustering quality
print()
print('Clustering quality (for reference):')
print('  NMI = {:.3f}  (how well pseudo-labels match ground truth)'.format(nmi))
print('  {} clusters found from {} real IDs'.format(n_clusters, len(set(g_pids))))
